// AUTO-GENERATED by @aquila/stories compiler. Do not edit by hand.

import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../characters';
import { Portrait } from '../portraits';
import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "二十點四十分。", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "基座已經在校史館後方暫存區了。防颱布蓋在上面，邊角用灰色膠帶壓住——和鐘樓、裝卸區、醫務室出現過的是同一種。兩個工作人員站在旁邊抽菸，雨傘撐在頭上，雨從傘沿滑下來，在地面匯成小水窪。", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言站在走廊轉角。他已經在這裡站了三分鐘了。", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）基座從校史館推到後方暫存區。白板上寫的流程是——暫存，等監控切線後轉往禮堂後台。但許星棠和韓越沒有跟基座走。", background: Background.Chapter_4_Ch4_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看得很清楚。基座被推到暫存區的時候，韓越和許星棠沒有往禮堂方向去。他們繞了一個彎，從暫存區側門出去，沿著校史館外牆，往後門的方向走了。", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他們不是在護送基座。他們是繞到基座背面去。", background: Background.Chapter_4_Ch4_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他等了三十秒。確認工作人員沒有注意到他。然後他跟了上去。", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校史館後方的走廊比前面暗得多。這裡不是展覽區，沒有遊客，沒有燈光設計——只有應急照明燈發出的昏黃微光，間隔很遠地嵌在天花板上，每兩盞之間有一段完全黑暗的間隙。牆面是重新粉刷過的白色，但潮氣讓下半截泛黃，像長了一層淺色的苔。", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走得很慢。腳步貼著地面。校服的橡膠鞋底在潮濕的瓷磚上發出很輕的、幾乎聽不到的摩擦聲——但在這條安靜得只有雨聲的走廊裡，每一聲都被放大了。", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）只跟到後門。如果他們進地下，我就停。", background: Background.Chapter_4_Ch4_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這是他給自己設的限制。他不是偵探小說裡那種衝進黑暗的熱血主角。他是一個已經死了三次的人。他知道衝動的代價是什麼。", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我的目標不是追他們。是確認他們在做什麼。只要看見他們從哪扇門進去，我就可以離開。回宿舍。等下一輪。", background: Background.Chapter_4_Ch4_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他轉過第二個彎。", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "前面。大約十五公尺外的走廊盡頭，有一扇金屬門。門框上方有攝影機——校慶期間臨時加裝的那種，黑色半球罩，紅色指示燈亮著。門左邊掛著一塊牌子：「校史館後門／僅限授權人員進入」。", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越站在門前。許星棠在他身後。", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越從脖子上的掛帶裡抽出一張卡——藍底白字，和普通的舞台組通行證不一樣。他把卡貼上門旁的感應器。嗶。綠燈亮了。門開了一條縫。", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他們進去了。", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）那是校史館後門卡。行政組的。今天上午在門禁借用表上看到的——「校史館後門卡，行政組，展品移動，晚間使用」。", background: Background.Chapter_4_Ch4_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）韓越怎麼會有行政組的卡？", background: Background.Chapter_4_Ch4_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他靠在牆角。心跳在加速。不是因為恐懼——是因為推理。三條線在這扇門後面交會：韓越的通行權限、許星棠的相機、基座的底板。", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他們知道基座底下有東西。", background: Background.Chapter_4_Ch4_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他正要轉身離開——他設了限制，只跟到後門，他們進去了，他該停了——", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他聽到了。", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門沒有完全關上。金屬門在自動閉門器的作用下慢慢合攏，但在最後兩公分的縫隙裡，聲音漏了出來。走廊太安靜了。雨聲填不滿這種密閉空間的空隙。他聽到了——", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "後門卡只剩一次機會。", background: Background.Chapter_4_Ch4_Act13_S0, portrait: Portrait.HanYue_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越的聲音。壓得很低。但穿透力很強。像在對許星棠下達最後確認。", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "我只要拍到底板。", background: Background.Chapter_4_Ch4_Act13_S0, portrait: Portrait.XuXingtang_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠的聲音。平的。像在確認一項清單上的待辦事項。不帶情緒。不帶解釋。", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）底板。基座底板。他們要拍的是基座底下。他們知道基座裡面有東西——不是時間膠囊，是底板下面的東西。", background: Background.Chapter_4_Ch4_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的腳步已經往回轉了一半。他應該走。他設了限制。他答應自己了。", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）走吧。回宿舍。明天再查。下一輪再來。", background: Background.Chapter_4_Ch4_Act13_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後。", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "從門縫裡漏出來的聲音。比剛才更低。更碎。像韓越在搬什麼東西時隨口說了一句——", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "⋯⋯顧澤那邊的資料，如果底板裡有——", background: Background.Chapter_4_Ch4_Act13_S0, portrait: Portrait.HanYue_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言停住了。", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）顧澤。", background: Background.Chapter_4_Ch4_Act13_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他說了——顧澤。", background: Background.Chapter_4_Ch4_Act13_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊裡的雨聲好像突然變遠了。他耳朵裡只剩下那兩個字。顧澤。他父親的名字。從韓越嘴裡說出來的。", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他們知道我爸。", background: Background.Chapter_4_Ch4_Act13_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他們知道我爸和這件事有關。", background: Background.Chapter_4_Ch4_Act13_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "限制斷了。不是因為他衝動——是因為他沒辦法再走。有人提到了他父親的名字。在那扇門後面。和基座、底板、相機、後門卡連在一起。", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走向那扇金屬門。腳步比剛才快。不再壓著地面。門縫還在——自動閉門器的液壓阻尼很慢，門還沒有完全合上。他側身。擠了進去。", background: Background.Chapter_4_Ch4_Act13_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門在身後合上。嗒。金屬碰金屬的聲音。很輕。但很結實。", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門後是一條更窄的走廊。水泥牆面，沒有粉刷。天花板上的管線外露，螢光燈管有的亮有的不亮，明暗交替，像走在呼吸之間的間隙裡。地面有積水——淺的，不到一公分，但每一步踩下去都會濺起小水花。空氣比外面更冷，帶著一股陳舊的、混合了水泥和霉味的味道。", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看見了前面的兩個背影。韓越在前，許星棠在後。他們走得很快，轉入了一個彎道。", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）跟。只再跟一段。聽他們還會說什麼。", background: Background.Chapter_4_Ch4_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他加快腳步。走廊在前方分岔。左邊是向上的階梯，通向校史館展區；右邊繼續向下，通向更深的地方。他們走了右邊。", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他跟到分岔口。往下看——他們的背影在轉角消失了。往上看——安全的，明的，通向校史館的。", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他們往下走了。往下是地下。我說過——如果他們進地下，我就停。", background: Background.Chapter_4_Ch4_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站在分岔口。呼吸很穩。心跳很快。他知道規則。他設了規則。", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但規則裡沒有說——如果他們提到我爸的名字怎麼辦。", background: Background.Chapter_4_Ch4_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他正要做出決定——", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "身後。遠處。走廊入口的方向。腳步聲。不止一個人。對講機的沙沙聲。手電筒的光束從門縫底下漏進來，在天花板上晃動。", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他回頭。門的另一邊有人來了。", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.Voice, character: "聲音", dialogue: "後方清一下，基座要從這邊推過去。", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校安。不止一個。兩三個。手電筒。對講機。他們正在朝這邊走。", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）林主任的人。", background: Background.Chapter_4_Ch4_Act13_S1, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他面前只有兩條路。往回走——撞上校安。被帶回指揮室。線索斷在這裡。向上走——回到校史館展區，但可能被入口處的工作人員看見。向下走——跟進地下。他知道監控只拍到入口和後門，不拍地下深處。他知道。他從白板上看到了。", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）只暫時躲一下。等他們過去。", background: Background.Chapter_4_Ch4_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他選擇了向下。", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "腳步踩上潮濕的階梯。金屬扶手冰涼。他往下走了五級、十級。階梯轉了一個彎。上面的聲音變遠了。手電筒的光消失了。", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他在階梯轉角處停下來。蹲下。背靠牆壁。等。", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門那邊傳來校安的聲音——", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.SecurityGuard, character: "校安", dialogue: "這裡面沒人吧？", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.SecurityGuard, character: "校安", dialogue: "監控剛切過，入口沒人。", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他們沒有進來。他們只是從門外路過，確認了一下。然後腳步聲繼續往前，手電筒的光繼續往另一個方向晃，聲音越來越遠。", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）走了。", background: Background.Chapter_4_Ch4_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站起來。準備往回走。回到上面的分岔口。回到安全的地方。", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但他看了一眼下面。", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "階梯繼續向下。更深。更暗。遠處有一盞燈在閃，像心跳不穩。牆上有水痕——不是新的，是舊的，乾了又濕、濕了又乾留下的水漬，像一面記錄了很多次雨天的牆。", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他想起韓越說的話。", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「顧澤那邊的資料，如果底板裡有——」", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那句話沒有說完。底板裡有什麼？和他爸有什麼關係？為什麼韓越知道他爸的名字？", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_4_Ch4_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）只再走幾步。聽一聽。確認一下他們的方向。然後我就回去。", background: Background.Chapter_4_Ch4_Act13_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他往下走了。不是跑。不是衝。是壓著重心、一步一步地走。像一個已經給自己設了無數條紅線、正在一條一條跨過去的人——每跨一條，他都告訴自己「最後一條」。", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "二十一點十分。校史館後方維修走廊。地下階梯。雨聲從頭頂的管線裡傳下來，悶悶的，像有人在地面上敲鼓。", background: Background.Chapter_4_Ch4_Act13_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他已經在地面以下了。而他給自己設的最後一條紅線——只跟到後門——早已經被丟在身後。", background: Background.Chapter_4_Ch4_Act13_S1 },
];
